head.script:
scwin.rowFlag = "";
scwin.nowCountRow = 0;
scwin.nowCountRow2 = 0;
scwin.pos_groupCode = 0;
scwin.MSG_OP_ERR_204 = "@에 변경된 사항이 있습니다. \n변경사항을 저장 후 수행하십시오.";
scwin.MSG_OP_ERR_205 = "종료BAY가 시작BAY보다 작을 수 없습니다.";
scwin.MSG_OP_ERR_206 = "시작BAY를 먼저 입력하십시오.";
scwin.oldPosition = 0;
scwin.parent_wrkPlCd = null;
scwin.hid_con_blckCd = "";

scwin.onpageload = async function() {
    scwin.params = $c.data.getParameter();
    if (scwin.params != null && !$c.gus.cfIsNull(scwin.params["wrkPlCd"])) {
        scwin.parent_wrkPlCd = scwin.params["wrkPlCd"];
    }

    $c.gus.cfDisableBtnOnly([btn_subAdd, btn_subDel, btn_subCls]);

    scwin.f_setDataList();
};

scwin.onUdcCompleted = async function() {
    if (!$c.gus.cfIsNull(scwin.parent_wrkPlCd)) {
        ed_con_wrkPlCd.setValue(scwin.parent_wrkPlCd);
        scwin.f_Retrieve();
    }
};

scwin.f_setDataList = function() {
    for (let row = 0; row < 99; row++) {
        let value = "";
        if ((row + 1) < 10) {
            value = "0" + (row + 1);
        } else {
            value = "" + (row + 1);
        }
        ds_comboDataList.insertRow();
        ds_comboDataList.setCellData(row, "cd", value);
        ds_comboDataList.setCellData(row, "cdNm", value);
    }

    for (let row = 0; row < 9; row++) {
        ds_TierDataList.insertRow();
        ds_TierDataList.setCellData(row, "TierCD", "" + (row + 1));
        ds_TierDataList.setCellData(row, "TierNM", "" + (row + 1));
    }
};

scwin.f_AddRow = async function(intGubun) {
    if (ds_workPlaceInfo.getRowCount() != 0 && ds_workPlaceInfo.getCellData(ds_workPlaceInfo.getRowCount() - 1, "blckCd") != "") {
        let len = ds_workPlaceInfo.getCellData(ds_workPlaceInfo.getRowCount() - 1, "blckCd");
        let onelen = len.substring(0, 1);
        let t = escape(onelen);

        if (t.match(/^[a-z]+$/ig) == null) {
            await $c.win.alert("작업장별 BLOCK 정보의  첫번째 문자는 영문이여야 합니다.");
            ds_workPlaceInfo.setCellData(ds_workPlaceInfo.getRowCount() - 1, "blckCd", "");
            return;
        }
    }

    if (intGubun == 'main') {
        $c.gus.cfEnableBtnOnly([btn_subAdd, btn_subDel, btn_subCls]);

        scwin.nowCountRow = ds_workPlaceInfo.getRowCount();

        ds_workPlaceInfo.insertRow();

        let curPos = ds_workPlaceInfo.getRowPosition();

        if (scwin.nowCountRow == 0) {
            if (ed_con_wrkPlCd.getValue() != "") {
                ds_workPlaceInfo.setCellData(curPos, "wrkPlCd", ed_con_wrkPlCd.getValue());
            } else if (ed_con_wrkPlCd.getValue() == "") {
                scwin.f_openCommonPopUp(2, '', '', 'T', 'T');
            }
        } else if (scwin.nowCountRow > 0) {
            ds_workPlaceInfo.setCellData(curPos, "wrkPlCd", ds_workPlaceInfo.getCellData(0, "wrkPlCd"));
        }

        ds_workPlaceInfo.setCellData(curPos, "usblPyCnt", "");
        ds_workPlaceInfo.setCellData(curPos, "rmk", "");
        ds_workPlaceInfo.setCellData(curPos, "regId", "");
        ds_workPlaceInfo.setCellData(curPos, "regDtm", "");
        ds_workPlaceInfo.setCellData(curPos, "modId", "");
        ds_workPlaceInfo.setCellData(curPos, "modDtm", "");

        scwin.oldPosition = ds_workPlaceInfo.getRowPosition();

    } else if (intGubun == 'sub') {

        for (let i = 0; i < ds_workPlaceInfo.getRowCount(); i++) {
            if (ds_workPlaceInfo.getCellData(i, "blckCd") == "") {
                await $c.win.alert("ZONE 항목은 필수 입력입니다.");
                return;
            }
        }

        scwin.nowCountRow2 = ds_workPlaceInfoDetail.getRowCount();

        ds_workPlaceInfoDetail.insertRow();

        let curPos2 = ds_workPlaceInfoDetail.getRowPosition();
        let masterPos = ds_workPlaceInfo.getRowPosition();

        ds_workPlaceInfoDetail.setCellData(curPos2, "wrkPlCd", ds_workPlaceInfo.getCellData(masterPos, "wrkPlCd"));
        ds_workPlaceInfoDetail.setCellData(curPos2, "blckCd", ds_workPlaceInfo.getCellData(masterPos, "blckCd"));
        ds_workPlaceInfoDetail.setCellData(curPos2, "seq", "");

        if (scwin.nowCountRow2 == 0) {
            ds_workPlaceInfoDetail.setCellData(curPos2, "stBay", "01");
            ds_workPlaceInfoDetail.setCellData(curPos2, "endBay", "02");
            ds_workPlaceInfoDetail.setCellData(curPos2, "rw", "01");
            ds_workPlaceInfoDetail.setCellData(curPos2, "tier", "1");
        } else if (scwin.nowCountRow2 > 0) {
            let val = parseInt(ds_workPlaceInfoDetail.getCellData(scwin.nowCountRow2 - 1, "endBay"), 10);
            let stVar = val + 1;
            let endVar = val + 2;

            if (stVar > 99 || endVar > 99) {
                await $c.gus.cfAlertMsg("추가 BAY가 없습니다.");
                ds_workPlaceInfoDetail.undoRow(curPos2);
                return;
            }

            if (stVar < 10) stVar = "0" + stVar;
            if (endVar < 10) endVar = "0" + endVar;

            ds_workPlaceInfoDetail.setCellData(curPos2, "stBay", "" + stVar);
            ds_workPlaceInfoDetail.setCellData(curPos2, "endBay", "" + endVar);
            ds_workPlaceInfoDetail.setCellData(curPos2, "rw", "01");
            ds_workPlaceInfoDetail.setCellData(curPos2, "tier", "1");
        }

        ds_workPlaceInfoDetail.setCellData(curPos2, "rfpsblYn", "");
        ds_workPlaceInfoDetail.setCellData(curPos2, "regId", "");
        ds_workPlaceInfoDetail.setCellData(curPos2, "regDtm", "");
        ds_workPlaceInfoDetail.setCellData(curPos2, "modId", "");
        ds_workPlaceInfoDetail.setCellData(curPos2, "modDtm", "");
        ds_workPlaceInfoDetail.setCellData(curPos2, "cd", "");
        ds_workPlaceInfoDetail.setCellData(curPos2, "cdNm", "");
    }
};

scwin.f_Delrow = async function(gubun) {
    if (gubun == 'main') {
        let selectedRows = gr_workPlaceInfo.getCheckedIndex("chk");
        if (selectedRows && selectedRows.length > 0) {
            for (let i = selectedRows.length - 1; i >= 0; i--) {
                ds_workPlaceInfo.removeRow(selectedRows[i]);
            }
        } else {
            let curPos = ds_workPlaceInfo.getRowPosition();
            if (curPos >= 0) {
                if (ds_workPlaceInfo.getRowStatus(curPos) == "U") {
                    ds_workPlaceInfoDetail.removeAll();
                }
                ds_workPlaceInfo.removeRow(curPos);
            }
        }
    } else if (gubun == 'sub') {
        let selectedRows2 = gr_workPlaceInfoDetail.getCheckedIndex("chk");
        if (selectedRows2 && selectedRows2.length > 0) {
            for (let i = selectedRows2.length - 1; i >= 0; i--) {
                ds_workPlaceInfoDetail.removeRow(selectedRows2[i]);
            }
        } else {
            let curPos2 = ds_workPlaceInfoDetail.getRowPosition();
            if (curPos2 >= 0) {
                ds_workPlaceInfoDetail.removeRow(curPos2);
            }
        }
    }
};

scwin.f_Undo = async function() {
    ds_workPlaceInfoDetail.undoAll();
    let curPos = ds_workPlaceInfo.getRowPosition();
    if (curPos >= 0) {
        ds_workPlaceInfo.undoRow(curPos);
    }
};

scwin.f_Retrieve = async function() {
    if (!(await $c.gus.cfValidate([search_con]))) return;

    oGDS_view_cond.set("wrkPlCd", ed_con_wrkPlCd.getValue());
    oGDS_view_cond.set("blckCd", scwin.hid_con_blckCd);

    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_checkIsUpdate = async function() {
    if (ds_workPlaceInfo.getUpdatedIndex().length > 0) {
        await $c.gus.cfAlertMsg(scwin.MSG_OP_ERR_204, ["BLOCK정보"]);
        return false;
    }
    return true;
};

scwin.f_checkUsblPyCnt1 = async function() {
    let curPos = ds_workPlaceInfo.getRowPosition();
    if (curPos >= 0 && ds_workPlaceInfo.getCellData(curPos, "usblPyCnt") == "0") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["가용평수"]);
        return false;
    }
    return true;
};

scwin.f_Save = async function() {
    if (!(await $c.gus.cfValidate([gr_workPlaceInfo]))) return;
    if (!(await $c.gus.cfValidate([gr_workPlaceInfoDetail]))) return;

    let masterPos = ds_workPlaceInfo.getRowPosition();
    for (let i = 0; i < ds_workPlaceInfoDetail.getRowCount(); i++) {
        ds_workPlaceInfoDetail.setCellData(i, "blckCd", ds_workPlaceInfo.getCellData(masterPos, "blckCd"));
        if (ds_workPlaceInfoDetail.getCellData(ds_workPlaceInfoDetail.getRowPosition(), "cdNm") != "") {
            let cdNmVal = ds_workPlaceInfoDetail.getCellData(ds_workPlaceInfoDetail.getRowPosition(), "cdNm");
            let chkRow = -1;
            for (let j = 0; j < ds_workPlaceInfoDetail.getRowCount(); j++) {
                if (ds_workPlaceInfoDetail.getCellData(j, "cdNm") == cdNmVal) {
                    chkRow = j;
                    break;
                }
            }
            if (chkRow != ds_workPlaceInfoDetail.getRowPosition()) {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_032, ["품목분류"]);
                ds_workPlaceInfoDetail.setCellData(ds_workPlaceInfoDetail.getRowPosition(), "cdNm", "");
                ds_workPlaceInfoDetail.setCellData(ds_workPlaceInfoDetail.getRowPosition(), "cd", "");
                ds_workPlaceInfoDetail.setCellData(ds_workPlaceInfoDetail.getRowPosition(), "grpCd", "");
                ds_workPlaceInfoDetail.setCellData(ds_workPlaceInfoDetail.getRowPosition(), "cdEngNmAbbr", "");
                return;
            }
        }
    }

    if (ds_workPlaceInfo.getUpdatedIndex().length == 0 && ds_workPlaceInfoDetail.getUpdatedIndex().length == 0) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
    } else {
        let chk = await $c.win.confirm("저장하시겠습니까?");
        if (chk) {
            scwin.rowFlag = "SAVE";
            await $c.sbm.execute(sbm_save);
        }
    }
};

scwin.f_checkUsblPyCnt = async function() {
    let cnt = ds_workPlaceInfo.getRowCount();
    for (let i = 0; i < cnt; i++) {
        if (parseInt(ds_workPlaceInfo.getCellData(i, "usblPyCnt")) == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["가용평수"]);
            return false;
        }
    }
    return true;
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects([ed_con_wrkPlCd, ed_con_wrkPlNm]);
    ds_workPlaceInfo.removeAll();
    ds_workPlaceInfoDetail.removeAll();
    totalRows1.setValue(0);
    totalRows2.setValue(0);
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            udc_con_wrkPl.ilCommonPopUp(scwin.callbackWrkPl1,
                pCode,
                pName,
                pClose,
                null,
                null,
                null,
                null,
                ',,,1,,,,,',
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                "작업장,작업장코드,작업장명"
            );
            break;

        case 2:
            udc_con_wrkPl.ilCommonPopUp(scwin.callbackWrkPl2,
                pCode,
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                "작업장,작업장코드,작업장명"
            );
            break;
    }
};

scwin.callbackWrkPl1 = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_con_wrkPlCd, ed_con_wrkPlNm);
};

scwin.callbackWrkPl2 = function(rtnList) {
    if (rtnList != null) {
        let curPos = ds_workPlaceInfo.getRowPosition();
        ds_workPlaceInfo.setCellData(curPos, "wrkPlCd", rtnList[0]);
    } else if (rtnList == null) {
        ds_workPlaceInfo.undoRow(0);
    }
};

scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    $c.gus.cfClearPairObj(pairObj);

    let pVal = $c.gus.cfGetValue(inObj);

    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.f_gridOnPopup = async function() {
    let curPos = ds_workPlaceInfoDetail.getRowPosition();
    if (curPos < 0) return;
    let param = ds_workPlaceInfoDetail.getCellData(curPos, "cdNm");
    let url = "/ui/ds/op/wrkplan/stvwrkplan/op_204_04_01p.xml";
    let obj = {
        cdNm: param
    };
    let rtnValue = await $c.win.openPopup(url, {
        width: 720,
        height: 500,
        modal: true,
        data: obj
    });
    if (rtnValue != null) {
        if (rtnValue[0] != "") { ds_workPlaceInfoDetail.setCellData(curPos, "grpCd", rtnValue[0]); }
        if (rtnValue[1] != "") { ds_workPlaceInfoDetail.setCellData(curPos, "cd", rtnValue[1]); }
        if (rtnValue[2] != "") { ds_workPlaceInfoDetail.setCellData(curPos, "cdEngNmAbbr", rtnValue[2]); }
        if (rtnValue[3] != "") { ds_workPlaceInfoDetail.setCellData(curPos, "cdNm", rtnValue[3]); }
    }
};

scwin.sbm_save_submitdone = async function(e) {
    scwin.rowFlag = "";
    await $c.gus.cfAlertMsg(MSG_CM_INF_001);
};

scwin.sbm_save_submiterror = async function(e) {
    await $c.gus.cfAlertMsg(e.responseJSON ? e.responseJSON.errorMsg : "저장 중 오류가 발생했습니다.");
};

scwin.sbm_retrieve_submitdone = async function(e) {
    let rowCnt = ds_workPlaceInfo.getRowCount();
    totalRows1.setValue(rowCnt);
    totalRows2.setValue(ds_workPlaceInfoDetail.getRowCount());
    if (rowCnt == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        $c.gus.cfDisableBtnOnly([btn_subAdd, btn_subDel, btn_subCls]);
    } else if (rowCnt > 0) {
        $c.gus.cfEnableBtnOnly([btn_subAdd, btn_subDel, btn_subCls]);
    }
};

scwin.sbm_retrieve_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.sbm_retrieveSub_submitdone = function(e) {
    let rowCnt = ds_workPlaceInfoDetail.getRowCount();
    totalRows2.setValue(rowCnt);
};

scwin.sbm_retrieveSub_submiterror = function(e) {
    $c.gus.cfShowError(e);
};

scwin.ds_workPlaceInfo_onrowpositionchange = async function(info) {
    let row = info.row;

    if (row >= 0) {
        scwin.hid_con_blckCd = ds_workPlaceInfo.getCellData(row, "blckCd");
        oGDS_view_cond.set("blckCd", scwin.hid_con_blckCd);

        await $c.sbm.execute(sbm_retrieveSub);

        if (ds_workPlaceInfo.getRowStatus(row) == "C") {
            $c.gus.cfEnableKeyData();
        } else {
            $c.gus.cfDisableKeyData();
        }
    } else {
        ds_workPlaceInfoDetail.removeAll();
    }

    if (ds_workPlaceInfo.getRowCount() == 0) {
        $c.gus.cfDisableBtnOnly([btn_subAdd, btn_subDel, btn_subCls]);
    }
};

scwin.ds_workPlaceInfo_canrowpositionchange = async function(info) {
    if (scwin.rowFlag == "") {
        if (btn_Save.getDisabled() == false && ds_workPlaceInfoDetail.getUpdatedIndex().length > 0) {
            let chk = await $c.win.confirm(MSG_CM_CRM_005);
            if (chk) {
                let curPos = ds_workPlaceInfo.getRowPosition();
                if (ds_workPlaceInfo.getRowStatus(curPos) != "C") {
                    ds_workPlaceInfo.undoRow(curPos);
                }
                return true;
            } else {
                return false;
            }
        }
    }
    return true;
};

scwin.gr_workPlaceInfo_oncellclick = function(rowIndex, columnIndex, columnId) {
    scwin.oldPosition = rowIndex;
};

scwin.gr_workPlaceInfo_oneditend = async function(rowIndex, columnIndex, columnId, value, oldValue) {
    if (columnId == "blckCd") {
        if (ds_workPlaceInfo.getRowCount() > 0) {
            if (ds_workPlaceInfo.getCellData(rowIndex, columnId) != "") {
                let chkRow = -1;
                for (let j = 0; j < ds_workPlaceInfo.getRowCount(); j++) {
                    if (j != rowIndex && ds_workPlaceInfo.getCellData(j, "blckCd") == ds_workPlaceInfo.getCellData(rowIndex, columnId)) {
                        chkRow = j;
                        break;
                    }
                }
                if (chkRow != -1) {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_032, ["ZONE코드"]);
                    ds_workPlaceInfo.setCellData(rowIndex, "blckCd", "");
                }
            }
        }
    }
};

scwin.gr_workPlaceInfoDetail_ontextimageclick = function(rowIndex, columnIndex) {
    scwin.f_gridOnPopup();
};

scwin.gr_workPlaceInfoDetail_oncloseup = async function(rowIndex, columnIndex, columnId) {
    let sVal = "";
    let eVal = "";
    let curVal = "";
    let msg = [];
    let status = "";

    if (columnId != "stBay" && columnId != "endBay") return;

    curVal = ds_workPlaceInfoDetail.getCellData(rowIndex, columnId);
    if (columnId == "stBay") {
        msg = ["시작BAY"];
    } else {
        msg = ["종료BAY"];
    }

    if (ds_workPlaceInfoDetail.getCellData(rowIndex, "stBay") == "" && ds_workPlaceInfoDetail.getCellData(rowIndex, "endBay") != "") {
        await $c.gus.cfAlertMsg("시작BAY부터 입력하십시오.");
        ds_workPlaceInfoDetail.setCellData(rowIndex, "endBay", "");
        ds_workPlaceInfoDetail.setRowPosition(rowIndex);
        gr_workPlaceInfoDetail.setFocusedCell(rowIndex, "stBay");
        return;
    }

    for (let i = 0; i < ds_workPlaceInfoDetail.getRowCount(); i++) {
        sVal = ds_workPlaceInfoDetail.getCellData(i, "stBay");
        eVal = ds_workPlaceInfoDetail.getCellData(i, "endBay");

        if (i != rowIndex) {
            if (curVal > sVal) {
                if (curVal > eVal) {
                    status = "T";
                } else if (curVal <= eVal) {
                    await $c.gus.cfAlertMsg("[" + (i + 1) + "]번째 BAY와 중복됩니다.");
                    ds_workPlaceInfoDetail.setCellData(rowIndex, columnId, "");
                    return false;
                }
            } else if (curVal < sVal) {
                if (curVal >= eVal) {
                    await $c.gus.cfAlertMsg("시작BAY가 중복됩니다.");
                    ds_workPlaceInfoDetail.setCellData(rowIndex, columnId, "");
                    return false;
                } else if (curVal < eVal) {
                    status = "T";
                }
            } else {
                await $c.gus.cfAlertMsg("[" + (i + 1) + "]번째 BAY와 중복됩니다.");
                ds_workPlaceInfoDetail.setCellData(rowIndex, columnId, "");
                return false;
            }
        } else if (i == rowIndex) {
            if (sVal != "" && eVal != "" && sVal > eVal) {
                await $c.gus.cfAlertMsg("시작BAY가 종료BAY보다 큽니다.");
                ds_workPlaceInfoDetail.setCellData(rowIndex, columnId, "");
                return false;
            } else {
                status = "T";
            }
        }
    }
};

scwin.gr_workPlaceInfoDetail_oneditend = function(rowIndex, columnIndex, columnId, value, oldValue) {
    scwin.f_gridOnPopup();
};

scwin.ed_con_wrkPlCd_onblur = function(e) {
    scwin.f_chkOpenCommonPopUp(ed_con_wrkPlCd, ed_con_wrkPlNm, 1);
};

scwin.btn_retrieve_onclick = function(e) {
    scwin.f_Retrieve();
};

scwin.btn_fieldClear_onclick = function(e) {
    scwin.f_FieldClear();
};

scwin.btn_Save_onclick = function(e) {
    scwin.f_Save();
};

scwin.btn_pathAdd_onclick = function(e) {
    scwin.f_AddRow('main');
};

scwin.btn_pathDel_onclick = function(e) {
    scwin.f_Delrow('main');
};

scwin.btn_pathCls_onclick = function(e) {
    scwin.f_Undo();
};

scwin.btn_subAdd_onclick = function(e) {
    scwin.f_AddRow('sub');
};

scwin.btn_subDel_onclick = function(e) {
    scwin.f_Delrow('sub');
};

scwin.btn_subCls_onclick = function(e) {
    let curPos = ds_workPlaceInfoDetail.getRowPosition();
    if (curPos >= 0) {
        ds_workPlaceInfoDetail.undoRow(curPos);
    }
};
